+  char *end = nullptr;
+  long parsed = std::strtol(value, &end, 0);
+  if (end == value || parsed <= 0) {
+    return fallback;
+  }
+  return static_cast<int>(parsed);
+}
+
+__device__ __forceinline__ void fold(uint4 &acc, uint4 v) {
+  acc.x += v.x;
+  acc.y ^= v.y + 0x9e3779b9u;
+  acc.z += v.z ^ acc.x;
+  acc.w ^= v.w + acc.y;
+}
+
+} // namespace
+
+extern "C" __global__ __launch_bounds__(kThreadsPerBlock, 4)
+void hbm_read_bandwidth_kernel(const uint4 *__restrict__ input,
+                               uint4 *__restrict__ sink,
+                               std::uint64_t vec_count) {
+  const std::uint64_t tid =
+      static_cast<std::uint64_t>(blockIdx.x) * blockDim.x + threadIdx.x;
+  const std::uint64_t stride =
+      static_cast<std::uint64_t>(blockDim.x) * gridDim.x;
+  const std::uint64_t step = stride * 8;
+  uint4 acc = make_uint4(0x12345678u ^ static_cast<unsigned>(tid),
+                         0xabcdef01u + static_cast<unsigned>(tid),
+                         0x13579bdfu, 0x2468ace0u);
+
+  std::uint64_t i = tid;
+#pragma unroll 1
+  for (; i + 7 * stride < vec_count; i += step) {
+#pragma unroll
+    for (int u = 0; u < 8; ++u) {
+      fold(acc, input[i + static_cast<std::uint64_t>(u) * stride]);
+    }
+  }
+
+  for (; i < vec_count; i += stride) {
+    fold(acc, input[i]);
+  }
+
+  // This almost-never-taken side effect keeps every thread's read reduction live
+  // without adding material write traffic to the timed streaming pass.
+  const unsigned guard = acc.x ^ acc.y ^ acc.z ^ acc.w;
+  if (__builtin_expect(guard == 0x51f15eedu, 0)) {
+    sink[tid & 1023u] = acc;
+  }
+}
