+  const int timed_iters = env_int("HBM_TIMED_ITERS", kDefaultTimedIters);
+  const int blocks_per_cu = env_int("HBM_BLOCKS_PER_CU", kDefaultBlocksPerCu);
+  const int blocks = std::max(1, prop.multiProcessorCount * blocks_per_cu);
+
+  uint4 *input = nullptr;
+  uint4 *sink = nullptr;
+  HIP_CHECK(hipMalloc(&input, static_cast<size_t>(buffer_bytes)));
+  HIP_CHECK(hipMalloc(&sink, 1024 * sizeof(uint4)));
+
+  HIP_CHECK(hipMemset(input, 0xa5, static_cast<size_t>(buffer_bytes)));
+  HIP_CHECK(hipMemset(sink, 0, 1024 * sizeof(uint4)));
+  HIP_CHECK(hipDeviceSynchronize());
+
+  for (int i = 0; i < warmup_iters; ++i) {
+    hbm_read_bandwidth_kernel<<<blocks, kThreadsPerBlock>>>(input, sink,
