+  }
+  HIP_CHECK(hipGetLastError());
+  HIP_CHECK(hipDeviceSynchronize());
+
+  hipEvent_t start = nullptr;
+  hipEvent_t stop = nullptr;
+  HIP_CHECK(hipEventCreate(&start));
+  HIP_CHECK(hipEventCreate(&stop));
+
+  std::vector<float> elapsed_ms;
+  elapsed_ms.reserve(timed_iters);
+  for (int i = 0; i < timed_iters; ++i) {
+    HIP_CHECK(hipEventRecord(start, nullptr));
+    hbm_read_bandwidth_kernel<<<blocks, kThreadsPerBlock>>>(input, sink,
+                                                            vec_count);
+    HIP_CHECK(hipEventRecord(stop, nullptr));
+    HIP_CHECK(hipGetLastError());
+    HIP_CHECK(hipEventSynchronize(stop));
+    float ms = 0.0f;
+    HIP_CHECK(hipEventElapsedTime(&ms, start, stop));
+    elapsed_ms.push_back(ms);
+  }
+
+  uint4 host_sink{};
+  HIP_CHECK(hipMemcpy(&host_sink, sink, sizeof(host_sink),
+                      hipMemcpyDeviceToHost));
+
+  std::sort(elapsed_ms.begin(), elapsed_ms.end());
+  const float median_ms = elapsed_ms[elapsed_ms.size() / 2];
+  const double seconds = static_cast<double>(median_ms) * 1.0e-3;
+  const double bandwidth_gbps = static_cast<double>(buffer_bytes) / seconds / 1.0e9;
+
+  std::printf("HBM_BANDWIDTH_GBPS=%.2f\n", bandwidth_gbps);
+  std::printf("buffer_bytes=%llu\n",
+              static_cast<unsigned long long>(buffer_bytes));
+
+  if ((host_sink.x ^ host_sink.y ^ host_sink.z ^ host_sink.w) == 0xffffffffu) {
+    std::fprintf(stderr, "sink=%08x\n", host_sink.x);
+  }
+
+  HIP_CHECK(hipEventDestroy(start));
+  HIP_CHECK(hipEventDestroy(stop));
+  HIP_CHECK(hipFree(sink));
+  HIP_CHECK(hipFree(input));
+  return 0;
+}
